class Solution:
    def amountOfTime(self, root, start):
        from collections import defaultdict, deque
        adj = defaultdict(list)
        stack = [(root, None)]
        while stack:
            node, par = stack.pop()
            if not node:
                continue
            if par is not None:
                adj[node.val].append(par)
                adj[par].append(node.val)
            stack.append((node.left, node.val))
            stack.append((node.right, node.val))
        # BFS distances
        dist = {start: 0}
        q = deque([start])
        far = 0
        while q:
            u = q.popleft()
            for v in adj[u]:
                if v not in dist:
                    dist[v] = dist[u] + 1
                    far = max(far, dist[v])
                    q.append(v)
        return far

