class Solution:
    def amountOfTime(self, root, start):
        self.ans = 0
        def dfs(node):
            if not node:
                return 0, False
            ld, lf = dfs(node.left)
            rd, rf = dfs(node.right)
            if node.val == start:
                self.ans = max(self.ans, ld, rd)
                return 1, True
            if lf:
                self.ans = max(self.ans, ld + rd)
                return ld + 1, True
            if rf:
                self.ans = max(self.ans, ld + rd)
                return rd + 1, True
            return max(ld, rd) + 1, False
        dfs(root)
        return self.ans

