var amountOfTime = function(root, start) {
    let ans = 0;
    const dfs = (node) => {
        if (!node) return [0, false];
        const [ld, lf] = dfs(node.left);
        const [rd, rf] = dfs(node.right);
        if (node.val === start) {
            ans = Math.max(ans, ld, rd);
            return [1, true];
        }
        if (lf) {
            ans = Math.max(ans, ld + rd);
            return [ld + 1, true];
        }
        if (rf) {
            ans = Math.max(ans, ld + rd);
            return [rd + 1, true];
        }
        return [Math.max(ld, rd) + 1, false];
    };
    dfs(root);
    return ans;
};
